import{bV as e,aL as t,u as l,G as o}from"./chunks/framework.BfzMay2U.js";const h=JSON.parse('{"title":"consul集群角色选举Raft算法","description":"","frontmatter":{"title":"consul集群角色选举Raft算法","date":"2023-01-15T21:28:10.000Z","categories":["Deploy"],"tags":["consul","raft"]},"headers":[],"relativePath":"views/deploy/consul-raft.md","filePath":"views/deploy/consul-raft.md"}'),r={name:"views/deploy/consul-raft.md"};function i(c,a,d,s,n,u){return t(),l("div",null,[...a[0]||(a[0]=[o('<h1 id="consul-集群角色选举-raft-算法" tabindex="-1">consul 集群角色选举 Raft 算法 <a class="header-anchor" href="#consul-集群角色选举-raft-算法" aria-label="Permalink to &quot;consul 集群角色选举 Raft 算法&quot;">​</a></h1><h2 id="raft-算法" tabindex="-1">Raft 算法 <a class="header-anchor" href="#raft-算法" aria-label="Permalink to &quot;Raft 算法&quot;">​</a></h2><ul><li>解决了分布式中领导选举和一致性问题</li><li>比较出名的共识算法，比如<code>redis</code>哨兵模式和<code>consul</code></li></ul><h3 id="重要因素" tabindex="-1">重要因素 <a class="header-anchor" href="#重要因素" aria-label="Permalink to &quot;重要因素&quot;">​</a></h3><ul><li>任期机制，<code>raft</code>是终身任期的，只要服务没有问题，被选择的领导者节点一直都是领导者</li><li>心跳机制，它决定领导者是否能有效的和跟随者通信</li><li>随机的选举超时时间</li><li>先到先得</li><li>过半投票机制，收到过半的投票才能算领导者</li></ul><h3 id="角色" tabindex="-1">角色 <a class="header-anchor" href="#角色" aria-label="Permalink to &quot;角色&quot;">​</a></h3><ul><li><code>Follower</code>追随者，接受领导者发送的消息，当心跳超时时，主动推荐自己为候选人</li><li><code>Candidate</code>候选人，发送<code>rpc</code>消息，让其他节点投票给自己，票数过半时，成为领导者</li><li><code>Leader</code>领导者，向其他节点发送心跳，只要心跳不超时一直为领导者</li></ul><p><a href="https://raft.github.io/" target="_blank" rel="noreferrer">raft 官网地址</a></p><p>这里有一个动画，可以帮助我们进行理解。</p>',9)])])}const p=e(r,[["render",i]]);export{h as __pageData,p as default};
